insert into asignaturas (codigo, nombre, es_principal) values
  ('HIS', 'Historia', false),
  ('CIU', 'Educación para la Ciudadanía', false),
  ('EMP', 'Emprendimiento y Gestión', false),
  ('FIL', 'Filosofía', false)
insert into dcd (asignatura_id, codigo, descripcion, subnivel) values
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.1', 'Indagar y analizar la teoría de la abiogénesis que explica el origen de la vida, e interpretar las distintas evidencias científicas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.11', 'Usar modelos y describir la función del ADN como portador de la información genética que controla las características de los organismos y la transmisión de la herencia, y relacionar el ADN con los cromosomas y los genes. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.13', 'Experimentar con los procesos de mitosis, meiosis, y demostrar la trasmisión de la información genética a la descendencia por medio de la fertilización. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.14', 'Describir las leyes de Mendel, diseñar patrones de cruzamiento y deducir porcentajes genotípicos y fenotípicos en diferentes generaciones. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.16', 'Indagar la teoría cromosómica de la herencia, y relacionarla con las leyes de Mendel. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.17', 'Investigar las causas de los cambios del ADN que producen alteraciones génicas, cromosómicas y genómicas, e identificar semejanzas y diferencias entre estas', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.18', 'Indagar y describir los biomas del mundo e interpretarlos como sitios donde se evidencia la evolución de la biodiversidad en respuesta a los factores geográficos y climáticos', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.19', 'Indagar en estudios científicos la biodiversidad del Ecuador, analizar los patrones de evolución de las especies nativas y endémicas representativas de los diferentes ecosistemas, y explicar su megadiversidad. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.2', 'Identificar los elementos y compuestos químicos de la atmósfera de la Tierra primitiva, y relacionarlos con la formación abiogénica de las moléculas orgánicas que forman parte de la materia viva. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.20', 'Reflexionar acerca de la importancia social, económica y ambiental de la biodiversidad, e identificar la problemática y los retos del Ecuador frente al manejo sostenible de su patrimonio natural. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.21', 'Indagar y examinar las diferentes actividades humanas que afectan a los sistemas globales, e inferir la pérdida de biodiversidad a escala nacional, regional y global. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.22', 'Interpretar las estrategias y políticas nacionales e internacionales para la conservación de la biodiversidad insitu y ex situ, y la mitigación de problemas ambientales globales, y generar una actitud crítica, reflexiva y responsable en favor del ambiente. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.23', 'Evaluar el estado de los ecosistemas marinos y costeros de Ecuador, analizando la Convención de las Naciones Unidas sobre el Derecho del Mar (CONVE- MAR) y las estrategias globales o regionales para la conservación y el uso sostenible de los recursos marítimos. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.24', 'Analizar críticamente los marcos legales internacionales y compararlos con los de Ecuador, analizando su efectividad en la protección de los ecosistemas identificando iniciativas globales o regionales con un impacto positivo en el reconocimiento, promoción y la defensa de los derechos de la naturaleza', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.25', 'Debatir sobre los beneficios del uso del transporte público y compartido, considerando los impactos ambientales enfocados en el desarrollo sostenible. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.26', 'Proponer soluciones innovadoras a los desafíos socioambientales en la Amazonía ecuatoriana, integrando la conservación de la biodiversidad con el desarrollo social y económico de las comunidades locales promoviendo el respeto por la diversidad cultural y el compromiso con un desarrollo sostenible e inclusivo. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.4', 'Describir y comparar las características básicas de las biomoléculas a partir de sus procesos de síntesis y diversidad de polímeros. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.5', 'Usar modelos y describir la estructura, diversidad y función de las biomoléculas que constituyen la materia viva, y experimentar con procedimientos sencillos', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.6', 'Establecer las principales evidencias de las teorías científicas sobre la evolución biológica y analizar sobre el rol de la evolución con el proceso responsable del cambio y diversificación de la vida en la Tierra. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.7', 'Analizar los procesos de variación, aislamiento y migración, relacionados con la selección natural, y explicar el proceso evolutivo. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.9', 'Analizar los tipos de diversidad biológica a nivel de genes, especies y ecosistemas, y plantear su importancia para el mantenimiento de la vida en el planeta. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.1', 'Analizar las hipótesis sobre la evolución de las células procariotas y eucariotas basadas en la teoría de la endosimbiosis, y establecer semejanzas y diferencias entre ambos tipos de células. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.2', 'Describir los tipos de organización en las células animales y vegetales, compara experimentalmente sus diferencias, y establecer semejanzas y diferencias entre organelos. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.3', 'Usar modelos y describir la estructura y función de los organelos de las células eucariotas y diferenciar sus funciones en procesos anabólicos y catabólicos', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.5', 'Analizar la acción enzimática en los procesos metabólicos a nivel celular y evidenciar experimentalmente la influencia de diversos factores en la velocidad de las reacciones. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.1', 'Observar la forma y función de células y tejidos en organismos multicelulares animales y vegetales, e identificar su organización en órganos, aparatos y sistemas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.4', 'Describir los sistemas nervioso y endocrino en animales con diferente grado de complejidad, explicar su coordinación funcional para adaptarse y responder a estímulos del ambiente, y utilizar modelos científicos que demuestren la evolución de estos sistemas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.6', 'Observar y analizar los procesos de reproducción de animales, elaborar modelos del desarrollo embrionario, e identificar el origen de las células y la diferenciación de las estructuras. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.7', 'Examinar la estructura y función de los sistemas de transporte en las plantas, y describir la provisión de nutrientes y la excreción de desechos. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.9', 'Observar y analizar los procesos de reproducción de las plantas, elaborar modelos del desarrollo embrionario, e identificar el origen de las células y la diferenciación de las estructuras', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.1', 'Analizar el funcionamiento de los sistemas digestivo y excretor en el ser humano y explicar la relación funcional entre estos sistemas con flujogramas', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.10', 'Analizar las causas y consecuencias de las enfermedades que afectan al sistema neuroendocrino, y proponer medidas preventivas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.11', 'Interpretar la respuesta del cuerpo humano frente a microorganismos patógenos, describir el proceso de respuesta inmunitaria e identificar las anomalías de este sistema', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.12', 'Analizar la fecundación humana, concepción, el desarrollo embrionario y fetal, parto y aborto, y explicar de forma integral la función de la reproducción humana. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.13', 'Indagar acerca del crecimiento y desarrollo del ser humano, reflexionar sobre la sexualidad, la promoción, prevención y protección de la salud sexual, reproductiva y afectiva. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.14', 'Relacionar la salud sexual y reproductiva con las implicaciones en el proyecto de vida', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.2', 'Diseñar investigaciones experimentales y reconocer el valor nutricional de diferentes alimentos de uso cotidiano según la composición de sus biomoléculas, y establecer sus efectos en el metabolismo y la salud humana. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.3', 'Analizar y aplicar buenas prácticas que contribuyen a mantener un cuerpo saludable, y elaborar un plan de salud que considere una alimentación balanceada de acuerdo a su edad y actividad para asegurar su salud integral. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.4', 'Indagar acerca de las enfermedades nutricionales y desórdenes alimenticios más comunes que afectan a la población ecuatoriana, diseñar y ejecutar una investigación en relación a estas, su vínculo con la dimensión psicológica y comunicar por diferentes medios las medidas preventivas en cuanto a salud y nutrición', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.5', 'Usar modelos y describir los sistemas circulatorio y respiratorio en el ser humano, y establecer la relación funcional entre ellos, la cual mantiene el equilibrio homeostático. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.6', 'Indagar en diversas fuentes y sintetizar información sobre las enfermedades causadas por el consumo de tabaco, la falta de ejercicio, la exposición a contaminantes ambientales y a alimentos contaminados, y proponer medidas preventivas y la práctica de buenos hábitos. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.7', 'Usar modelos y describir el sistema osteoartromuscular del ser humano, en cuanto a su estructura y función, y proponer medidas para su cuidado. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.8', 'Establecer la relación entre la estructura y función el sistema nervioso y del sistema endocrino, en cuanto a su fisiología y la respuesta a la acción hormonal. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.9', 'Indagar en diversas fuentes sobre los efectos nocivos en el sistema nervioso ocasionados por el consumo de alcohol y otras drogas, y proponer medidas preventivas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.10', 'Interpretar modelos poblacionales que relacionan el crecimiento poblacional con diferentes modelos de desarrollo económico, y tomar una postura frente al enfoque del uso sustentable de los recursos naturales. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.11', 'Planificar y ejecutar una investigación sobre los diferentes avances tecnológicos que cubren las necesidades de la creciente población humana, con un enfoque de desarrollo sostenible. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.12', 'Evaluar planes de salud integral justificando la importancia de la salud mental de niños, niñas, adolescentes, personas jóvenes, adultas y adultas mayores', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.13', 'Evaluar las consecuencias sociales y ambientales de la aplicación de biotecnologías como la ingeniería genética y propone con otras personas de su edad soluciones a problemas locales', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.2', 'Indagar sobre la evolución de los pinzones de Galápagos que sustentó la teoría de la selección natural de Darwin, y analizar que se complementa con la teoría sintética de la evolución, propuesta por científicos contemporáneos', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.4', 'Indagar sobre el desarrollo de la Biotecnología en el campo de la Medicina y la Agricultura, e interpretar su aplicación en el mejoramiento de la alimentación y la nutrición de las personas. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.6', 'Indagar sobre la genética de poblaciones, analizar e inferir los resultados de binomios genéticos', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.7', 'Buscar, registrar y sistematizar información de diversas fuentes sobre el cáncer, y relacionarlo con el proceso de proliferación celular alterada. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.8', 'Indagar las aplicaciones de la ingeniería genética en la producción de alimentos y fármacos, sus implicaciones en la vida actual, y explicar el efecto de la terapia génica en el tratamiento de enfermedades humanas, considerando los cuestionamientos éticos y sociales', 'BGU'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.9', 'Indagar sobre los programas de salud pública sustentados en políticas estatales y en investigaciones socioeconómicas, y analizar sobre la importancia de la accesibilidad a la salud individual y colectiva, especialmente para poblaciones marginales, aisladas o de escasos recursos. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.1', 'Determinar el origen y evolución histórica del concepto “ciudadanía” en la Grecia y la Roma antigua. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.10', 'Discernir la igualdad como principio generador de opciones y oportunidades para todos. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.11', 'Establecer la relación entre individuo, sociedad y poder político, a partir de los derechos universales y desde el estudio de casos (la disidencia política, los desplazados, los refugiados). CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.12', 'Analizar la evolución del concepto “igualdad natural”, a partir del acceso al sufragio universal por los diferentes grupos sociales (personas esclavizadas, mujeres, analfabetos, personas privadas de libertad, migrantes, personas con discapacidad, grupos minoritarios y/o vulnerables, etc.)', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.13', 'Analizar los derechos y deberes de las personas en situación de movilidad humana para promover el respeto a los derechos humanos, la integración social y el acceso equitativo a servicios básicos en contextos de migración, desplazamiento o refugio', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.14', 'Reconocer y defender sus derechos como ciudadano o ciudadana, demostrando un profundo conocimiento de la legislación vigente y el valor de ejercerlos como parte de su autocuidado y crecimiento personal. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.15', 'Reconocer las características de condiciones laborales justas para garantizar un entorno de trabajo equitativo y respetuoso en su lugar de empleo. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.2', 'Determinar el origen y evolución histórica del concepto “derechos” a partir de la organización política de la sociedad (polis). CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.3', 'Analizar los procesos históricos que propiciaron la Declaración de los Derechos del Hombre y del Ciudadano, mediante el análisis multicausal de los mismos. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.4', 'Discutir los procesos históricos que propiciaron la Declaración de los Derechos de la Mujer y la Ciudadana, mediante el análisis multicausal de los mismos. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.5', 'Determinar la trascendencia de la Declaración Universal de los Derechos Humanos, desde la comprensión de su significado político. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.6', 'Reconocer la igualdad natural de los seres humanos y la protección de la vida frente a la arbitrariedad del poder desde el análisis político. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.7', 'Identificar y analizar cada una de las diferentes generaciones de derechos y el contexto histórico de su surgimiento. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.9', 'Explicar el principio de igualdad, a través del ejercicio del sufragio universal como condición de participación igualitaria. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.1', 'Contextualizar el nacimiento de la democracia moderna, considerando los procesos históricos que la alumbraron. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.10', 'Analizar la definición de democracia representativa, identificando sus límites y dificultades, considerando la distancia entre gobernantes y gobernados, electores y elegidos, los riesgos de tomar decisiones en nombre del electorado y la ausencia de rendición de cuentas. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.11', 'Establecer la importancia de la rendición de cuentas y la aplicación de sistemas de control como mecanismos para reforzar y afianzar los sistemas democráticos representativos. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.12', 'Definir el principio de deliberación a partir de sus implicaciones como procedimiento colectivo de toma de decisiones. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.13', 'Examinar la posible complementariedad de la democracia representativa y la democracia deliberativa. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.14', 'Evaluar la necesidad de la deliberación como esfera política, considerando su aplicabilidad y las dificultades que conlleva la realización del ideal deliberativo. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.15', 'Establecer las ventajas y las limitaciones de la democracia deliberativa, considerando aspectos como la posibilidad de expresión social, la falta de información del público, entre otros. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.16', 'Identificar los mecanismos de deliberación pública, considerando su complejidad y su aplicabilidad', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.18', 'Reconocer la democracia como una experiencia social enfocándose en el análisis de sus manifestaciones y expresiones en la vida cotidiana y en las prácticas ciudadanas comunes. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.19', 'Analizar ejemplos de procesos deliberativos en el hogar, la escuela y la comunidad, poniendo énfasis en los mecanismos que los propician, facilitan y/o dificultan. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.2', 'Explicar la democracia moderna mediante el análisis de su significado radical: inexistencia de títulos naturales para gobernar, como el principio de filiación, el buen nacimiento, el linaje, la riqueza, la edad o la meritocracia. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.20', 'Discutir nuevos mecanismos de expresión y prácticas deliberativas, considerando las diversas formas de relación entre los ciudadanos en los nuevos espacios (redes sociales, Internet, etc.). CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.21', 'Aplicar el diálogo y la deliberación como forma de consenso y disenso casos para contribuir a la formación de una cultura de paz. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.22', 'Justificar la importancia del respeto a las normas y señales de tránsito, proponiendo medidas para mejorar la seguridad para peatones, personas con discapacidad, movilidad reducida y grupos vulnerables', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.3', 'Determinar los parámetros sobre los que se construye el concepto de ciudadanía en la democracia moderna, su concepción y roles, a partir del análisis de las características de esta última. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.4', 'Discutir de manera informada la implicación de los principios de alternabilidad y de la despersonalización del poder como fundamentos de un sistema democrático pluralista. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.5', 'Determinar las contradicciones del significado de soberanía del pueblo, considerando la evolución del concepto y sus cambios sustanciales. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.6', 'Contrastar los derechos civiles y los derechos políticos, a partir del análisis de las características particulares de cada uno. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.7', 'Describir los procesos de búsqueda de la legitimidad del poder político, por medio del análisis de los mecanismos de legitimación social. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.9', 'Examinar el significado de la representación política, considerando las contribuciones de la democracia representativa. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.1', 'Explicar el desarrollo de la democracia en Ecuador desde un Estado excluyente en 1830, hasta llegar a la declaración de Estado plurinacional establecida en la Constitución del 2008. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.2', 'Discutir la cultura nacional fundamentada en la plurinacionalidad, tomando en cuenta los aportes que cada componente brinda desde su especificidad. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.3', 'Analizar y valorar cada uno de los fundamentos sociales del Ecuador (indígena, afroecuatoriano, mestizo y montubio) como un camino en la comprensión de la otredad y de la armonía social. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.4', 'Comprender y valorar los aportes particulares de cada cultura en la construcción de una sociedad intercultural. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.5', 'Determinar la evolución histórica de las demandas sociales de los pueblos y nacionalidades, en función de la construcción de un Estado incluyente y sostenible', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.6', 'Reconocer la democracia como forma paradójica, a partir de su dificultad para concretar las expectativas sociales (igualdad social, movilidad social, autonomía del individuo). CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.7', 'Identificar las limitaciones de la democracia, considerando la persistencia de exclusiones sociales, la tendencia a la corrupción y el surgimiento de nuevas élites', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.8', 'Explicar el carácter ambiguo y complejo de la política, a partir del análisis de las luchas sociales y las luchas políticas por el cumplimiento de los derechos sociales', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.9', 'Describir los alcances y limitaciones de la representación política otorgada a los representantes de la ciudadanía, reconociendo el derecho ciudadano de exigir la rendición de cuentas y/o la revocatoria del mandato', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.10', 'Identificar formas de republicanismo (federalismo, centralismo y confederalismo), a partir del análisis de determinados estados latinoamericanos', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.12', 'Explicar los roles que cumplen las funciones del Estado ecuatoriano a partir del análisis de los mecanismos de ordenamiento social, estructura y esquema de funcionamiento. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.13', 'Explicar cómo los ingresos de los gobiernos se utilizan para proveer bienes y servicios públicos, por qué es necesario pagar impuestos, y cómo ciertos servicios están protegidos por leyes o regulaciones de protección al consumidor. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.14', 'Evaluar la influencia de la gestión gubernamental en la desigualdad económica y social', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.2', 'Identificar y analizar el rol de cada uno de los componentes del Estado: fuerzas armadas, derecho (leyes), tribunales de justicia, burocracia, cárceles, aparatos ideológicos (medios de comunicación), etc., y su impacto en las distintas clases sociales. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.3', 'Diferenciar Estado, nación y gobierno a través de la identificación de sus funciones específicas y su rol histórico. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.4', 'Determinar el significado de las Asambleas Nacionales Constituyentes desde las revoluciones del siglo XVIII. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.6', 'Identificar al pueblo como sujeto de las Asambleas Constituyentes, a partir del análisis del principio de soberanía. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.7', 'Comparar las cartas constitucionales del Ecuador atendiendo a la progresión de los derechos de ciudadanía', 'BGU'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.9', 'Señalar los postulados del republicanismo, tomando en cuenta las diferencias con otros modelos de organización política. CS', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.1', 'Realizar producciones artísticas (una canción, un dibujo, una escultura, un monólogo, una instalación, etc.) a partir de temas de interés personal o social, cuestionamientos, preocupaciones o ideas relevantes para la juventud', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.10', 'Explorar su propia identidad, reconociendo sus fortalezas, debilidades, valores y metas a través de la automotivación al buscar oportunidades de crecimiento personal para gestionar sus emociones y tomar decisiones conscientes', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.2', 'Autoevaluarse durante los procesos de creación artística usando criterios técnicos, reconociendo las propias emociones y realizando los ajustes necesarios para lograr el producto deseado', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.6', 'Planificar de forma razonada los procesos propios de creación o interpretación artística, considerando las necesidades de expresión y comunicación, y elaborar un guion con los pasos a seguir y los recursos necesarios', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.7', 'Identificar un ámbito o forma de expresión artística de interés (cerámica, joyería, mimo, percusión corporal, video arte, etc.), utilizar recursos para el autoaprendizaje (libros, videos, aprendizaje entre pares, consulta a especialistas) y aplicar los conocimientos y habilidades adquiridos en la creación de un pequeño proyecto o producto artístico', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.1', 'Seleccionar, ensayar e interpretar obras musicales y escénicas (teatro, musicales, títeres, danza, ópera, etc.) asumiendo distintos roles (actor, director, escenógrafo, etc.) y contribuyendo a la consecución del resultado esperado', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.2', 'Representar historias reales o inventadas a través de un guion gráfico, una secuencia sonora, una representación teatral, una creación corporal o un video', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.3', 'Diseñar y desarrollar pequeños proyectos artísticos colectivos centrados en un tema de interés individual o social (discriminación, contaminación sonora, género, etc.) previendo todas las fases del proceso, desde su creación hasta su difusión y presentación', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.4', 'Ensayar y grabar en video o audio distintas versiones de una improvisación o interpretación/representación artística (musical, dramática, corporal, etc.), revisar las diferentes versiones y reflexionar en grupo sobre los aspectos positivos y mejorables de cada una de ellas', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.5', 'Documentar, con fotografías, dibujos, registros sonoros o audiovisuales, los procesos creativos y las exposiciones o representaciones colectivas realizadas, y crear catálogos, programas radiofónicos, cortos u otros productos que den cuenta de los mismos', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.6', 'Participar en las distintas fases del proceso creativo (identificar un tema, investigar, explorar opciones, seleccionar y desarrollar ideas, recibir críticas, revisar y perfeccionar, interpretar o exponer), crear una obra original (de danza, música, escultura, pintura, cine, etc.), presentarla y debatir los resultados con la audiencia, con un artista invitado, un crítico u otro especialista', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.8', 'Indagar sobre la música de compositores y compositoras del repertorio clásico o popular, y componer una pieza o canción con un estilo similar al de los compositores elegidos; ensayarla, grabarla y publicarla en una web o un blog para que los oyentes puedan escucharla y comentarla', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.1', 'Investigar, analizar y comparar los recursos usados por artistas compositores, coreógrafos, dramaturgos, etc. para comunicar determinadas ideas, temas o conceptos (la naturaleza, eventos históricos, problemáticas sociales, optimismo, pesimismo, etc.) y para despertar emociones o sentimientos (alegría, tristeza, tensión, ira, etc.) en los oyentes o espectadores, y crear presentaciones multimedia que ilustren cómo se consigue el efecto deseado en cada forma de expresión artística', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.11', 'Investigar sobre los procesos formativos para dedicarse profesionalmente a distintos ámbitos del arte o la cultura y sobre la vida y el trabajo de algunos profesionales y elaborar videos con entrevistas breves o documentales que ilustren distintas opciones', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.12', 'Reconocer los materiales, las herramientas y las técnicas del grafiti y otras formas de arte urbano mediante la observación del entorno cotidiano o fotografías de estas representaciones en las ciudades, y crear una exposición virtual de imágenes relacionadas con el tema', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.13', 'Colaborar con sus pares para diseñar y construir una instalación artística que represente un espacio específico con materiales del medio aportando con ideas a un proyecto artístico colectivo, valorando las aportaciones de los demás en el desarrollo de un proyecto artístico asumiendo responsabilidades individuales dentro de un proyecto grupal y cumplir con los plazos establecidos', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.4', 'Reconocer a artistas y agentes culturales (individuales; femeninos y masculinos; colectivos; institucionales; etc.), obras y manifestaciones culturales del Ecuador, y relacionarlos con sus contextos históricos y sociales', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.5', 'Identificar y describir distintos tipos de manifestaciones y productos culturales y artísticos utilizando un lenguaje técnico, expresando puntos de vista personales, y mostrando una actitud de escucha y receptividad hacia las opiniones de otras personas', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.6', 'Reconocer y explicar diferentes maneras de entender y representar una idea, un sentimiento o una emoción en obras y manifestaciones artísticas y culturales de distintos momentos históricos y de diversas culturas', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.7', 'Analizar y valorar producciones artísticas y eventos culturales usando criterios técnicos y reconociendo las emociones que estos suscitan, y escribir críticas o comentarios para un periódico escolar, un blog personal o colectivo, una red social, etc., adecuando el lenguaje al medio utilizado', 'BGU'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.9', 'Buscar información sobre distintas formas de expresión en el arte contemporáneo (arte de acción, body art, instalaciones, happening, video arte, acción poética, performance, etc.) y elaborar una presentación o cartel (impreso o digital) que reúna los datos más importantes y algunas imágenes o videos ilustrativos', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.1', 'Reconocer a los juegos como manifestaciones constantes en la historia del hombre y relacionarlas con sus contextos de origen, su cultura específica y los sentidos y significados que le permiten a sus participantes convertirlos en una posible práctica recreativa', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.2', 'Reconocer cómo impactan los juegos en las diferentes dimensiones del sujeto, en la social (como facilitador de relaciones interpersonales), en la motriz (su influencia como motivador en el desarrollo de las capacidades coordinativas y condicionales), en la afectiva (la presencia de las emociones al jugar), en la cognitiva (en la toma de decisiones a la hora de resolver los problemas que le presenta el juego), etc', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.3', 'Identificar y participar de juegos modificados (de bate y campo, de cancha dividida, de blanco y diana y de invasión), cooperativos (como categoría que involucra otros juegos), reconociendo diferencias y similitudes con prácticas deportivas y maneras en que participa/juega para alcanzar sus objetivos, utilizando tácticas y estrategias posibles y realizando adecuaciones que considere necesarias', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.5', 'Participar de juegos colectivos reconociendo la importancia del trabajo en equipo (posibilidades y dificultades), de cooperar y oponerse y el papel de la comunicación motriz entre los jugadores, para resolver diferentes situaciones de juego y alcanzar sus objetivos', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.1', 'Reconocer la diferencia entre las prácticas gimnásticas como prácticas sistemáticas (para mejorar la condición física: capacidades coordinativas y condicionales, flexibilidad, velocidad, resistencia y fuerza) y la práctica gimnástica como práctica deportiva (aeróbica, artística, rítmica, acrosport, entre otras) para poder elegir cómo realizarlas de manera consciente, segura y saludable', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.2', 'Reconocer la necesidad de mejorar de modo saludable la condición física (capacidad que tienen los sujetos para realizar actividad física) para favorecer la participación en diferentes prácticas corporales, así como en acciones cotidianas', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.3', 'Construir ejercicios que mejoren la condición física y elaborar entrenamientos básicos para ponerlos en práctica, tomando como punto de partida su estado de inicio y las prácticas corporales hacia las cuales están orientados', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.5', 'Reconocer posibilidades de dominio corporal en la ejecución de movimientos y manejo de objetos durante las prácticas gimnásticas, para mejorarlos de manera consciente, segura y saludable', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.1', 'Reconocer las prácticas corporales expresivo-comunicativas como producciones valiosas e identitarias para sus protagonistas (con orígenes, contextos de producción y sentidos/ significados), y a la vez como posibles favorecedoras de la socialización y vinculación entre pares y con la cultura', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.2', 'Explorar e identificar diferentes tipos de danzas (tradicionales, populares, contemporáneas, entre otras), sus pasos básicos y sus coreografías y las posibilidades de crear nuevas y propias formas de danzar y expresarse corporalmente', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.3', 'Identificar los requerimientos (motores, emocionales, cognitivos, entre otros) que presentan diferentes prácticas expresivo-comunicativas y vincularlos con sus características (pasos básicos, música, duración, coreografía), para tomar decisiones sobre los modos de participación en ellas según los objetivos individuales y colectivos', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.4', 'Identificar y producir creaciones escénicas colectivas, vinculando más de una práctica corporal (como lo hacen el circo, la murga, los carnavales, entre otras), para crear y comunicar mensajes', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.5', 'Crear acciones y secuencias motrices utilizando diferentes recursos expresivos (intencionalidad expresiva de diferentes movimientos, según tiempo y espacio: lento-rápido, simultaneo-alternado, continuo-discontinuo, atrás-adelante, otros), desde la necesidad propia de manifestarse mediante el lenguaje corporal para enriquecer las posibilidades de comunicación individual y colectiva', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.6', 'Diferenciar los roles de espectadores y protagonistas, construyendo maneras de participación respetuosa en ambos, para transferirlas a situaciones en la vida cotidiana', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.1', 'Participar en diversas prácticas deportivas (individuales, colectivas, abiertas, cerradas, de contacto, entre otras) reconociendo sus diferencias según los ámbitos en que se practican (recreativo, amateur, federativo, alto rendimiento, entre otros), sus objetivos y los modos de alcanzarlos, para poder elegirlas, apropiarlas y continuar practicándolas a lo largo de sus vidas', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.2', 'Participar en prácticas deportivas comprendiendo la lógica interna (principios y acciones tácticas) de cada una y realizando ajustes técnicos, tácticos y estratégicos, en función de las reglas y requerimientos (motores, emocionales, cognitivos, sociales) para su resolución eficaz y confortable', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.3', 'Analizar el reglamento de los deportes y reconocerlo como conjunto de normas producidas por las federaciones, que marcan los límites y oportunidades de actuación, para tomar decisiones sobre los modos de participación que le permitan alcanzar los objetivos de dicha práctica', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.5', 'Reconocer la importancia del trabajo en equipo, la ayuda y la cooperación (como requisito para la oposición), para lograr el objetivo de las prácticas deportivas y poder participar en ellas de manera segura y saludable dentro y fuera del colegio', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.6', 'Participar en diferentes prácticas deportivas utilizando diferentes acciones técnicas y tácticas que favorezcan la continuidad del juego, reconociendo que las ejecuciones técnicas y respuestas tácticas cobran sentido en los contextos de juego (y en función del reglamento)', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.8', 'Reconocer los valores del juego limpio (en función del respeto a los acuerdos y reglas) y participar en prácticas deportivas en coherencia con ellos, para transferir esos valores a situaciones cotidianas', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.9', 'Comprender la necesidad de una preparación física adecuada y coherente con las prácticas deportivas, en función de sus objetivos (recreativo, federativo, de alto rendimiento) y requerimientos motrices, para minimizar los riesgos de lesiones y optimizar el desempeño seguro en el deporte de que se trate', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.1', 'Percibir y tomar conciencia de su estado corporal (respiración, postura temperatura, acciones musculares, posiciones, otros) en movimiento y en reposo, durante la realización de prácticas corporales para mejorar la participación consciente', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.3', 'Reconocer percepciones y sensaciones favorecedoras y obstaculizadoras del deseo de moverse (dolor, fatiga, entusiasmo, placer, entre otras), para tomar decisiones personales que colaboren con la participación sistemática en prácticas corporales', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.4', 'Reconocer el impacto de las representaciones sociales sobre el “lo femenino” y “lo masculino” en la constitución de la identidad corporal, para analizar críticamente sus sentidos y significados como facilitadores u obstaculizadores de la construcción de la competencia motriz', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.5', 'Reconocer la influencia de las percepciones de sí y de las demás personas sobre el propio desempeño, para analizarlas críticamente y construir posibilidades de participación', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.6', 'Analizar críticamente los vínculos entre los intereses y valores que portan los modelos estéticos hegemónicos y estereotipos de movimientos en relación a la singularidad de los sujetos y sus contextos', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.1', 'Identificar las demandas de las prácticas corporales para mejorar la condición física de base y el logro de los objetivos personales', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.3', 'Reconocer los beneficios que la actividad física puede aportar a su salud y su condición física, como un estado que puede mejorarse o deteriorarse en función del tipo y pertinencia de las actividades físicas y prácticas corporales que realiza', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.4', 'Reconocer la importancia de las diferencias individuales durante la participación en diferentes prácticas corporales, para identificar las maneras más saludables de alcanzar objetivos personales', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.5', 'Reconocer la importancia de los controles médicos previos y posteriores a la realización de prácticas corporales sistemáticas, como promotores de condiciones de participación responsable y saludable', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.6', 'Elaborar y poner en práctica planes básicos de trabajo propios, para mejorar la condición física de partida en función de los objetivos a alcanzar, los conocimientos sobre las actividades pertinentes para hacerlo y los cuidados a tener en cuenta para minimizar riesgos y optimizar resultados positivos', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.7', 'Reconocer la importancia del cuidado personal, comunitario y ambiental (seguridad e higiene) antes, durante y luego de la realización de diferentes prácticas corporales, para favorecer que la participación sea segura, saludable y placentera', 'BGU'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.8', 'Discriminar las acciones adecuadas a seguir en caso de siniestros de tránsito mediante simulaciones, asegurando una participación segura y efectiva en situaciones de emergencia', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.1', 'Describir y explicar los conceptos básicos financieros de un emprendimiento, tales como ingresos, costos, gastos e inversión, punto de equilibrio y sus proyecciones futuras como elemento fundamental para las proyecciones', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.10', 'Elaborar un estado de pérdidas y ganancias básico mediante la aplicación de las cuentas contables y la ecuación contable en un caso de estudio', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.2', 'Distinguir los diferentes tipos de costos y gastos que puede tener un emprendimiento para determinar detenidamente el capital de trabajo necesario para un emprendimiento', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.3', 'Identificar la obligatoriedad jurídica de llevar contabilidad de acuerdo con lo establecido por las normas tributarias como elemento fundamental para determinar la forma de llevar la contabilidad', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.4', 'Deducir la importancia de la contabilidad como elemento de control financiero del emprendimiento', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.5', 'Explicar las principales normas contables relacionadas con la partida doble para establecer los impactos en las cuentas', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.6', 'Clasificar las principales cuentas contables con su respectivo nombre para personificarlas, mediante la determinación de la naturaleza de su función en los asientos contables, tales como caja, bancos, cuentas por cobrar, inventarios, activos fijos, depreciación, capital, cuentas por pagar, préstamos bancarios, capital', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.7', 'Identificar los componentes básicos del activo, pasivo, patrimonio, ingresos, costos y gastos, de acuerdo con la normativa contable, para clasificar adecuadamente las cuentas contables', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.8', 'Interpretar las cuentas contables mediante la identificación de los cambios que causan las transacciones en los activos, pasivos y patrimonios, reflejados en la cuenta por partida doble', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.9', 'Elaborar un balance general básico mediante la aplicación de los principios, conceptos, técnicas contables y la normatividad vigente', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.1', 'Elaborar un mapeo de los requisitos legales básicos para iniciar actividades de emprendimiento que permitan formalizarlo', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.2', 'Identificar las obligaciones legales que debe cumplir un emprendedor como elemento fundamental para la operación del mismo. E', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.4', 'Aplicar los conocimientos tributarios en el llenado de los formularios básicos del SRI (RISE, IVA e Impuesto a la Renta)', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.5', 'Comprender los factores que afectan el poder adquisitivo del dinero, el impacto de los intereses compuestos en el ahorro evaluando las ventajas y desventajas de diversos productos de inversión', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.1', 'Proponer y definir productos o servicios determinados por necesidades de su entorno', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.10', 'Analizar los delitos financieros existentes, como el robo de identidad, fraudes, estafas, entre otros, para tomar decisiones informadas y precautelar su integridad', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.2', 'Describir y explicar los componentes del diseño de la investigación de campo para obtener información certera sobre el tema que se desea investigar o profundizar', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.4', 'Ejecutar una investigación de campo entre los potenciales clientes/ usuarios determinados para establecer las necesidades de la zona geográfica, de tal manera que se determinen las potenciales ideas de emprendimiento', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.5', 'Describir los conocimientos estadísticos básicos para tabular los datos recabados en una investigación de campo', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.6', 'Presentar la información obtenida en la investigación de campo de forma resumida y concisa en función de su utilidad para la toma de decisiones', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.7', 'Analizar estadísticamente la información de mercado (oferta y demanda) a partir de la representación gráfica de los datos procesados en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, estudios de medidas de tendencia central (media, mediana, moda)', 'BGU'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.8', 'Utilizar metodologías para interpretar datos estadísticos como fundamento para la toma de decisiones y la selección de las ideas de emprendimiento con mayor probabilidad de éxito', 'BGU'),
