  ((select id from asignaturas where codigo = 'MAT'), 'M.5.3.4', 'Calcular e interpretar el coeficiente de variación de un conjunto de datos (agrupados y no agrupados) para una mayor comprensión de la representatividad que tienen las medidas de tendencia central y tener un juicio crítico sobre las respuestas obtenidas o presentadas en medios de información', 'BGU'),
  ((select id from asignaturas where codigo = 'MAT'), 'M.5.3.5', 'Determinar los cuantiles (cuartiles, deciles y percentiles) para datos no agrupados y para datos agrupados', 'BGU'),
  ((select id from asignaturas where codigo = 'MAT'), 'M.5.3.7', 'Reconocer los experimentos y eventos en un problema de texto, y aplicar el concepto de probabilidad y los axiomas de probabilidad en la resolución de problemas', 'BGU'),
  ((select id from asignaturas where codigo = 'QUI'), 'Q.5.1.1', 'Analizar y clasificar las propiedades de los gases que se generan en la industria y aquellos que son más comunes en la vida y que inciden en la salud y el ambiente. CN', 'BGU'),
  ((select id from asignaturas where codigo = 'QUI'), 'Q.5.1.11', 'Establecer y diferenciar las fuerzas intermoleculares partiendo de la descripción del puente de hidrógeno, fuerzas de London y de Van der Walls, y dipolo-dipolo', 'BGU'),
