  ((select id from asignaturas where codigo = 'CN'), 'CN.2.3.13', 'Indagar, mediante el uso de las TIC y otros recursos, la propagación de la luz y experimentarla en diferentes medios', 'Elemental'),
  ((select id from asignaturas where codigo = 'CN'), 'CN.2.3.14', 'Reconocer mediante actividades prácticas y discusiones guiadas, los niveles de ruido en entornos urbanos y rurales, y describir cómo estos afectan la calidad de vida', 'Elemental'),
