  ((select id from asignaturas where codigo = 'CN'), 'CN.2.4.10', 'Indagar, por medio de la experimentación, y describir las características y la formación del suelo; reconocerlo como un recurso natural', 'Elemental'),
  ((select id from asignaturas where codigo = 'CN'), 'CN.2.4.13', 'Indagar y describir las características del agua, sus usos y conservación y destacar la importancia de conservar las fuentes de agua dulce', 'Elemental'),
  ((select id from asignaturas where codigo = 'CN'), 'CN.2.4.15', 'Identificar los residuos sólidos que se generan en su hogar y localidad clasificándolos según su composición y características; y, propone acciones para su disposición final y reducción', 'Elemental'),
